// Filter Candidates for Follow-up
// Returns only leads who need a follow-up email

const outreachItems = $('Get Outreach Sheet').all();
const repliesItems = $('Get Replies Sheet').all();
const suppressionItems = $('Get Suppression Sheet').all();

const FOLLOWUP_DAYS = 5;
const now = new Date();
const cutoffDate = new Date(now.getTime() - FOLLOWUP_DAYS * 24 * 60 * 60 * 1000);

// Build sets for O(1) lookup
const repliedWebsites = new Set();
repliesItems.forEach(r => {
  const w = (r.json.outreach_website || '').toLowerCase().replace(/\/$/, '');
  if (w) repliedWebsites.add(w);
});

const suppressedEmails = new Set();
suppressionItems.forEach(s => {
  const e = (s.json.email || '').toLowerCase().trim();
  if (e) suppressedEmails.add(e);
});

// Filter
const candidates = outreachItems.filter(item => {
  const r = item.json;

  // 1. Must be sent
  if (r.status !== 'sent') return false;

  // 2. Must have email
  if (!r.email || !r.email.trim()) return false;

  // 3. Must have generated_at and be older than 5 days
  const genStr = r.generated_at || r.date_generated;
  if (!genStr) return false;
  const genDate = new Date(genStr);
  if (isNaN(genDate.getTime())) return false;
  if (genDate > cutoffDate) return false;

  // 4. Lead must NOT have replied
  const website = (r.website || '').toLowerCase().replace(/\/$/, '');
  if (repliedWebsites.has(website)) return false;

  // 5. Lead must NOT be in suppression
  const email = (r.email || '').toLowerCase().trim();
  if (suppressedEmails.has(email)) return false;

  // 6. Must NOT have followup_at already set
  if (r.followup_at && String(r.followup_at).trim() !== '') return false;
  if (r.followup_status === 'sent' || r.followup_status === 'replied') return false;

  return true;
}).map(item => {
  const r = item.json;
  // Pass through original fields needed for follow-up generation
  return {
    json: {
      website: r.website,
      email: r.email,
      company_name: r.company_name,
      city: r.city,
      country: r.country,
      language: r.language,
      score: r.score,
      original_subject_a: r.subject_a,
      original_subject_b: r.subject_b,
      original_preheader: r.preheader,
      original_body: r.body,
      original_message_id: r.message_id || '',
      original_generated_at: r.generated_at || r.date_generated,
      days_since_sent: Math.floor((now - new Date(r.generated_at || r.date_generated)) / (1000 * 60 * 60 * 24))
    }
  };
});

return candidates;

// Build Follow-up Prompt for Claude
const lead = $json;

const systemPrompt = `Je bent een ervaren cold email copywriter. Je schrijft follow-up emails in het Nederlands voor B2B outreach naar Nederlandse vastgoedmakelaars.

REGELS:
- Schrijf in het Nederlands (formeel "u" vorm)
- Maximaal 60 woorden in body
- Geen agressieve sales taal
- Geen "ik wilde even checken" cliches
- Wees direct en respectvol
- Sluit af met "Groet, Anton"

KIES EEN VAN DEZE 3 STRATEGIEEN op basis van de oorspronkelijke email:

STRATEGIE 1 - BUMP (zachte herinnering):
Korte, vriendelijke herinnering. Geen druk. Bijvoorbeeld:
"Misschien gemist tussen de drukte. Geen probleem als het nu niet uitkomt."

STRATEGIE 2 - VALUE-ADD (extra waarde):
Voeg een concreet voordeel toe dat in de eerste email niet stond. Bijvoorbeeld een case study, statistiek, of specifiek aanbod.

STRATEGIE 3 - SOFT CLOSE (vriendelijk afsluiten):
Toon begrip dat het misschien geen prioriteit is. Geef de lead vrijheid. Dit werkt vaak verrassend goed door reverse psychology.
Bijvoorbeeld: "Ik sluit deze thread af. Mocht het later relevant worden, dan hoor ik het graag."

OUTPUT: alleen JSON, geen extra tekst:
{
  "strategy": "bump" | "value_add" | "soft_close",
  "body": "tekst van de follow-up email",
  "reasoning": "korte uitleg waarom deze strategie"
}`;

const userPrompt = `Schrijf een follow-up email voor deze lead die ${lead.days_since_sent} dagen geleden de eerste email kreeg en niet heeft geantwoord.

BEDRIJF: ${lead.company_name || 'onbekend'}
STAD: ${lead.city || ''}
LAND: ${lead.country || 'Nederland'}

OORSPRONKELIJKE EMAIL DIE ZE NIET BEANTWOORDDEN:
Subject: ${lead.original_subject_a || lead.original_subject_b || ''}
Preheader: ${lead.original_preheader || ''}
Body:
${lead.original_body || ''}

Genereer nu een follow-up. Output: alleen JSON.`;

return [{
  json: {
    ...lead,
    _claude_payload: {
      model: "claude-sonnet-4-5",
      max_tokens: 800,
      system: systemPrompt,
      messages: [
        { role: "user", content: userPrompt }
      ]
    }
  }
}];

// Parse Claude Response and prepare email
const claudeResponse = $json;
const leadData = $('Build Follow-up Prompt').item.json;

let parsed = {
  strategy: 'bump',
  body: '',
  reasoning: ''
};

try {
  // Claude API response structure: content[0].text contains the JSON
  const textContent = claudeResponse.content?.[0]?.text || claudeResponse.content || '';

  // Try to extract JSON from response (might be wrapped in markdown code blocks)
  let jsonStr = textContent;
  const jsonMatch = textContent.match(/```json\s*([\s\S]*?)\s*```/) || textContent.match(/```\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    jsonStr = jsonMatch[1];
  }

  // Find first { and last } to extract JSON
  const firstBrace = jsonStr.indexOf('{');
  const lastBrace = jsonStr.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
  }

  parsed = JSON.parse(jsonStr);
} catch (e) {
  // Fallback: use raw text as body
  parsed.body = (claudeResponse.content?.[0]?.text || '').slice(0, 500);
  parsed.strategy = 'bump';
  parsed.reasoning = 'parse_failed_fallback';
}

// Build subject — Re: original
const originalSubject = leadData.original_subject_a || leadData.original_subject_b || 'follow-up';
const subject = originalSubject.toLowerCase().startsWith('re:')
  ? originalSubject
  : `Re: ${originalSubject}`;

// Build email body
const body = parsed.body || '';

// Build HTML version
const htmlBody = body
  .split('\n')
  .map(line => line.trim() ? `<p>${line.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</p>` : '')
  .filter(Boolean)
  .join('\n');

// Generate followup tracking ID
const followupId = `followup_${parsed.strategy}_${new Date().toISOString()}`;

return [{
  json: {
    ...leadData,
    followup_strategy: parsed.strategy,
    followup_reasoning: parsed.reasoning,
    followup_subject: subject,
    followup_body: body,
    followup_html: htmlBody,
    followup_tracking_id: followupId,
    has_original_message_id: !!(leadData.original_message_id && leadData.original_message_id.startsWith('<'))
  }
}];

// Build Telegram Summary — runs ONCE after all follow-ups sent
// Aggregates results across all loop iterations
const allItems = $('Parse Claude Response').all();

const total = allItems.length;
const successful = allItems.filter(i => i.json.followup_status === 'sent' || !i.json.error).length;
const failed = total - successful;

const strategies = {
  bump: 0,
  value_add: 0,
  soft_close: 0
};

allItems.forEach(i => {
  const s = i.json.followup_strategy;
  if (strategies.hasOwnProperty(s)) strategies[s]++;
});

let msg = `📨 <b>FOLLOW-UP ОТЧЕТ</b>\n`;
msg += `<i>${new Date().toLocaleString('ru-RU', { timeZone: 'Europe/Moscow' })}</i>\n\n`;

if (total === 0) {
  msg += `Кандидатов на follow-up сегодня: <b>0</b>\n\n`;
  msg += `Это нормально, если:\n`;
  msg += `• Все письма за последние 5 дней уже получили ответ\n`;
  msg += `• Sender не отправлял писем 5+ дней назад\n`;
  msg += `• Все нужные follow-up уже отправлены ранее`;
} else {
  msg += `📤 <b>Отправлено follow-up:</b> ${successful} из ${total}\n`;
  if (failed > 0) {
    msg += `❌ <b>Ошибки:</b> ${failed}\n`;
  }
  msg += `\n<b>СТРАТЕГИИ:</b>\n`;
  if (strategies.bump > 0) msg += `🔄 Bump (мягкое напоминание): ${strategies.bump}\n`;
  if (strategies.value_add > 0) msg += `💎 Value-add (доп ценность): ${strategies.value_add}\n`;
  if (strategies.soft_close > 0) msg += `👋 Soft close (закрытие): ${strategies.soft_close}\n`;
  msg += `\n`;

  // Show first 5 companies
  const companies = allItems.slice(0, 5).map(i => {
    const j = i.json;
    return `• ${j.company_name || j.email} (${j.followup_strategy})`;
  });
  msg += `<b>ПЕРВЫЕ ${Math.min(5, total)} КОМПАНИЙ:</b>\n`;
  msg += companies.join('\n');
  if (total > 5) msg += `\n... и еще ${total - 5}`;
}

return [{
  json: {
    telegram_message: msg,
    total_candidates: total,
    successful: successful,
    failed: failed
  }
}];
